class Solution:
    def minimumOperationsToMakeKPeriodic(self, word: str, k: int) -> int:
        n = len(word)
        chunks = [word[i:i+k] for i in range(0, n, k)]
        from collections import Counter
        freq = Counter(chunks)
        return len(chunks) - max(freq.values())

